INSERT INTO products (id, name, category, price, description, images, dimensions, size_category, rooms, material, origin, stock) VALUES
  ('aaaaaaaa-0000-0000-0000-000000000001', 'Hereke Imperial Silk Rug', 'Handmade', 3850, 'A masterpiece of Turkish weaving from the imperial workshops of Hereke. This rug features a high knot density with pure silk threads, showcasing the classic "Seven Mountains" pattern.', ARRAY['https://placehold.co/1000x800', 'https://placehold.co/1000x800'], '4'' x 6''', 'Small', ARRAY['Bedroom', 'Office'], '100% Pure Silk', 'Hereke, Turkey', 1),
  ('aaaaaaaa-0000-0000-0000-000000000002', 'Antique Oushak Medallion', 'Vintage', 2450, 'A genuine vintage Oushak rug from the early 20th century. Known for its soft, muted palette and large-scale floral patterns, it brings a touch of history to any modern space.', ARRAY['https://placehold.co/1000x800', 'https://placehold.co/1000x800'], '9'' x 12''', 'Large', ARRAY['Living Room', 'Dining Room'], 'Hand-spun Wool', 'Uşak, Turkey', 1),
  ('aaaaaaaa-0000-0000-0000-000000000003', 'Anatolian Tribal Kilim', 'Kilim', 1200, 'Vibrant geometric patterns tell the story of Anatolian heritage. Each Kilim is unique, flat-woven by nomadic tribes using traditional techniques.', ARRAY['https://placehold.co/1000x800', 'https://placehold.co/1000x800'], '5'' x 7''', 'Medium', ARRAY['Living Room', 'Bedroom'], 'Hand-spun Wool', 'Anatolia, Turkey', 3),
  ('aaaaaaaa-0000-0000-0000-000000000004', 'Modern Machine-Woven Sultan', 'Machine', 450, 'A high-quality machine-woven rug that captures the essence of traditional Turkish designs. Durable, easy to clean, and perfect for high-traffic areas.', ARRAY['https://placehold.co/1000x800', 'https://placehold.co/1000x800'], '8'' x 10''', 'Large', ARRAY['Living Room', 'Dining Room', 'Hallway'], 'Heat-set Polypropylene', 'Gaziantep, Turkey', 15),
  ('aaaaaaaa-0000-0000-0000-000000000005', 'Vintage Isparta Floral', 'Vintage', 1850, 'A vintage Isparta rug featuring a dense floral field and a rich crimson border. These rugs are celebrated for their durability and classic Anatolian motifs.', ARRAY['https://placehold.co/1000x800'], '6'' x 9''', 'Medium', ARRAY['Living Room', 'Bedroom'], 'Wool on Cotton', 'Isparta, Turkey', 2),
  ('aaaaaaaa-0000-0000-0000-000000000006', 'Kayseri Silk-on-Silk Prayer Rug', 'Handmade', 2900, 'A fine Kayseri prayer rug, hand-knotted with silk on a silk foundation. The intricate mihrab design is a testament to the skill of Turkish artisans.', ARRAY['https://placehold.co/1000x800'], '3'' x 5''', 'Small', ARRAY['Bedroom', 'Office'], 'Pure Silk', 'Kayseri, Turkey', 1),
  ('aaaaaaaa-0000-0000-0000-000000000007', 'Machine-Woven Anatolian Runner', 'Machine', 180, 'A practical and stylish runner for your hallway. Features traditional Anatolian patterns in a modern, easy-care construction.', ARRAY['https://placehold.co/1000x800'], '2.5'' x 10''', 'Runner', ARRAY['Hallway'], 'Synthetic Blend', 'Gaziantep, Turkey', 20);
