INSERT INTO testimonials (name, location, title, text, date, rating, category) VALUES
  ('Sarah Jenkins', 'London, UK', 'Handmade Silk Rug review', 'The quality of the vintage Oushak I received is breathtaking. It completely transformed my client''s living space. The colors are even more vibrant in person. The craftsmanship is truly world-class.', 'October 21, 2025', 5, 'Handmade'),
  ('Michael Chen', 'New York, USA', 'Vintage Oushak review', 'A truly authentic piece of Anatolian history. The service was impeccable and the rug arrived perfectly packaged. Highly recommended for collectors who value heritage and quality.', 'November 12, 2025', 5, 'Vintage'),
  ('Emma Thompson', 'Sydney, AU', 'Modern Nomad review', 'I spent months looking for the right rug. Bisāṭ made it easy to find a piece that feels like it was made for our home. The texture is incredible and it feels so soft underfoot.', 'December 05, 2025', 5, 'Modern'),
  ('David Miller', 'Berlin, DE', 'Handmade Silk Rug review', 'The attention to detail is remarkable. You can tell this rug was made with love and patience. It''s not just a rug, it''s a piece of art that we will cherish for years.', 'January 15, 2026', 4, 'Handmade'),
  ('Elena Rossi', 'Milan, IT', 'Vintage Revival review', 'I was hesitant to buy such a large item online, but the team was so helpful with extra photos and videos. The rug is perfect and fits my space beautifully.', 'February 02, 2026', 5, 'Vintage'),
  ('James Wilson', 'Toronto, CA', 'Modern Nomad review', 'Excellent quality and fast shipping. The rug arrived in perfect condition. I love the minimalist design and the natural materials used.', 'March 10, 2026', 5, 'Modern');
